import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Using StringBuilder instead of fixed-size char array
        StringBuilder buffer = new StringBuilder();

        // Appending the user input to the StringBuilder
        buffer.append(name);

        // Printing out the contents of the buffer
        System.out.println("Hello, " + buffer.toString());
    }
}

### Explanation:
취약유형: Buffer Overflow
